def grade_practical_assessment(
    task_description: str,
    learner_prompt: str,
    learner_output: str,
    rubric: dict,
) -> dict:
    """Grade a practical certification assessment using a structured rubric.

    Assessor reviews and may override — this is a first-pass scoring tool.
    """
    rubric_text = "\n".join(
        f"- {criterion} ({weight} points): {description}"
        for criterion, (weight, description) in rubric.items()
    )
    prompt = f"""Grade this Claude training practical assessment. An assessor will review your scoring.

Task: {task_description}

Learner's prompt to Claude:
{learner_prompt}

Claude's output (as shown to learner):
{learner_output}

Rubric (total 100 points):
{rubric_text}

For each criterion, assign a score and provide one sentence of evidence.
Return JSON: {{ "scores": {{ criterion: {{ "score": int, "evidence": str }} }}, "total": int, "pass": bool, "summary": str }}
Pass threshold: 80 points."""

    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=600,
        messages=[{"role": "user", "content": prompt}],
    )
    return json.loads(resp.content[0].text)


result = grade_practical_assessment(
    task_description="Draft a first-response email to a customer who reports an incorrect direct debit amount",
    learner_prompt="Write a professional email to a bank customer who says we took the wrong amount from their account. Be empathetic and offer a callback.",
    learner_output="Dear Customer, Thank you for reaching out. I understand how concerning it can be to see an unexpected charge. I've flagged this for our team and a specialist will call you within 2 business days. Best regards, Support Team",
    rubric={
        "Tone and empathy": (25, "Message acknowledges impact without being generic"),
        "Compliance (no prohibited content)": (30, "No promise of refund; no speculation on cause; no internal process details"),
        "Conciseness": (20, "Under 120 words; no filler phrases"),
        "Clear next step": (25, "Specific action with a timeframe is stated"),
    },
)
print(f"Total: {result['total']}/100 — {'PASS' if result['pass'] else 'FAIL'}")
print(f"Summary: {result['summary']}")
